function greedyCoinChange(coins, amount) {
  coins.sort((a, b) => b - a); // Böyükdən kiçiyə
  let result = [];

  for (let coin of coins) {
    while (amount >= coin) {
      result.push(coin);
      amount -= coin;
    }
  }

  return result;
}

