// Two Pointers nümunəsi - Sorted Array-də iki ədədin cəmi
function twoSumSorted(arr, target) {
  let left = 0;
  let right = arr.length - 1;

  while (left < right) {
    let sum = arr[left] + arr[right];
    if (sum === target) {
      return [left, right];
    } else if (sum < target) {
      left++;
    } else {
      right--;
    }
  }
  return [-1, -1];
}

// Sliding Window - Maksimum subarray cəmi
function maxSubarraySum(arr, k) {
  let maxSum = 0;
  let windowSum = 0;

  // İlk pəncərəni hesabla
  for (let i = 0; i < k; i++) {
    windowSum += arr[i];
  }
  maxSum = windowSum;

  // Pəncərəni sürüşdür
  for (let i = k; i < arr.length; i++) {
    windowSum = windowSum - arr[i - k] + arr[i];
    maxSum = Math.max(maxSum, windowSum);
  }

  return maxSum;
}

